import React from 'react'
import classes from './Nav.module.css';
import logo1 from '../../Assets/ste logo.jpg';


const Nav = () => {
  return (
         <section className={classes.main}>
                   
                    <div className={classes.logo1}> 
                     
                    </div>

         
                   <div className={classes.nav}>
                      <ul>
                      <li><a className={classes.r1} href="#home">Home</a></li>
                      <li><a className={classes.r1} href="#About">News</a></li>
                      <li><a className={classes.r1}href="#product">Contact</a></li>
                      <li><a className={classes.r1} href="#about">About</a></li>
                        </ul>
                      </div>

           </section>
  )
}

export default Nav;
